const items = $input.all();
const now = new Date();
const cutoff = new Date(now.getTime() - 15 * 60 * 60 * 1000);

return items.filter(item => {
  const articleDate = new Date(item.json.article_date);
  return articleDate >= cutoff;
}).map(item => ({ json: item.json }));

const items = $input.all();
const urls = items
  .filter(item => !item.json.error && !item.json.message)
  .map(item => item.json.url || item.json.article_url || '')
  .filter(Boolean);
return [{ json: { archived_urls: urls, loaded: true } }];

const allItems = $input.all();

// Separate archive summary (has loaded marker) from articles
const archiveSummary = allItems.find(item => item.json.loaded === true);
const archivedUrls = new Set(archiveSummary?.json?.archived_urls || []);

// Articles are all items without the loaded marker
const articles = allItems.filter(item => item.json.loaded !== true);

const seenUrls = new Set();
return articles.filter(item => {
  const url = item.json.article_url || '';
  if (!url || archivedUrls.has(url) || seenUrls.has(url)) return false;
  seenUrls.add(url);
  return true;
}).map(item => ({ json: item.json }));

const N = 1; // 원하는 개수로 변경

const items = $input.all();

const topN = items
  .sort((a, b) => (b.json.score || 0) - (a.json.score || 0))
  .slice(0, N);

return topN.map(item => ({ json: item.json }));

