const items = $input.all();

return items.map((item) => {
  const output = item.json.output || '';
  let title = '';
  let summary = '';

  try {
    const parsed = JSON.parse(output);
    title = parsed.title || '';
    summary = parsed.summary || '';
  } catch(e) {
    const titleMatch = output.match(/"title"\s*:\s*"([^"]+)"/);
    const summaryMatch = output.match(/"summary"\s*:\s*"([\s\S]+?)"\s*\}/) ;
    title = titleMatch ? titleMatch[1] : '';
    summary = summaryMatch ? summaryMatch[1] : '';
  }

  return {
    json: {
      country: item.json.country || '기타',
      title,
      summary
    }
  };
});

const items = $input.all().filter(item => item.json.summary);

let marketData = '';

if ($('시장 데이터 조회 + 메시지 포맷').isExecuted) {
  const data = $('시장 데이터 조회 + 메시지 포맷').all();
  marketData = data?.[0]?.json?.message || '';
}

function escapeMarkdown(text) {
  return (text || '').replace(/([_*\[\]()~`>#+\-=|{}.!\\])/g, '\\$1');
}

const countryLabels = {
  '미국': '미국', 'US': '미국', 'USA': '미국',
  '중국': '중국', 'CN': '중국', 'China': '중국',
  '한국': '한국', 'KR': '한국', 'Korea': '한국',
  '기타': '기타'
};
const countryOrder = ['미국', '중국', '한국', '기타'];

const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const month = kst.getUTCMonth() + 1;
const day = kst.getUTCDate();

const grouped = {};
for (const item of items) {
  const raw = (item.json.country || '기타').trim();
  const label = countryLabels[raw] || '기타';
  if (!grouped[label]) grouped[label] = [];
  grouped[label].push({
    title: item.json.title || '',
    summary: item.json.summary
  });
}

let message = `안녕하세요\\.\n\\[${month}월 ${day}일 모닝 브리핑\\] 보내드립니다\\.`;

if (marketData) {
  message += '\n\n' + escapeMarkdown(marketData);
}

message += '\n\n\\[주요국 이슈\\]';

for (const country of countryOrder) {
  const articles = grouped[country];
  if (!articles || articles.length === 0) continue;
  message += `\n\n\\# ${country}\n`;
  message += articles.map(a =>
    `*${escapeMarkdown(a.title)}*\n${escapeMarkdown(a.summary)}`
  ).join('\n\n');
}

message += `\n\n\\[밑바닥리서치 텔레그램 채널 / 블로그\\]\nhttps://t\\.me/undergroundresearch36\nhttps://blog\\.naver\\.com/undergroundresearch`;

return [{ json: { message } }];

const items = $input.all();
let table = "| index | title | content |\n|---|---|---|\n";

items.forEach(item => {
  const idx = item.json.index ?? '';
  const title = (item.json.title || '').replace(/\|/g, '／').replace(/[\n\r]+/g, ' ');
  const content = (item.json.content || '').replace(/\|/g, '／').replace(/[\n\r]+/g, ' ').substring(0, 400);
  table += `| ${idx} | ${title} | ${content} |\n`;
});

return [{ json: { table } }];

const tableText = $input.first().json.output || '';

const lines = tableText.trim().split('\n')
  .map(l => l.trim())
  .filter(l => l.startsWith('|') && !/^\|[\s\-|]+\|$/.test(l));

if (lines.length < 2) {
  return [{ json: { error: 'Table parse failed', raw: tableText } }];
}

const headers = lines[0].split('|').slice(1, -1).map(h => h.trim());

return lines.slice(1).map(line => {
  const cells = line.split('|').slice(1, -1).map(c => c.trim());
  const obj = {};
  headers.forEach((h, i) => {
    const val = cells[i] ?? '';
    const num = Number(val);
    obj[h] = val !== '' && !isNaN(num) ? num : val;
  });
  return { json: obj };
});

