const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0.0.0 Safari/537.36';

let results = [];
let debugMsg = '';

try {
  const cookieRes = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://fc.yahoo.com',
    headers: { 'User-Agent': UA },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  const cookieHeader = cookieRes.headers['set-cookie'];
  const cookie = (Array.isArray(cookieHeader) ? cookieHeader[0] : (cookieHeader || '')).split(';')[0];

  const crumb = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://query1.finance.yahoo.com/v1/test/getcrumb',
    headers: { 'User-Agent': UA, 'Cookie': cookie },
  });

  const symbols = ['^DJI','^GSPC','^IXIC','AAPL','MSFT','GOOGL','AMZN','NVDA','META','TSLA','CL=F','^TNX','KRW=X'];
  const quoteData = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://query1.finance.yahoo.com/v7/finance/quote',
    headers: { 'User-Agent': UA, 'Cookie': cookie },
    qs: { symbols: symbols.join(','), crumb },
  });
  results = quoteData?.quoteResponse?.result || [];

} catch (e) {
  debugMsg = ` (오류: ${e.message})`;
}

const q   = (sym) => results.find(r => r.symbol === sym) || {};
const pct = (v) => (v != null) ? `${v >= 0 ? '+' : ''}${Number(v).toFixed(2)}%` : 'N/A';
const pr  = (v, d = 2) => (v != null) ? Number(v).toFixed(d) : 'N/A';

const dji  = q('^DJI');
const gspc = q('^GSPC');
const ixic = q('^IXIC');
const aapl = q('AAPL');
const msft = q('MSFT');
const googl = q('GOOGL');
const amzn = q('AMZN');
const nvda = q('NVDA');
const meta = q('META');
const tsla = q('TSLA');
const wti  = q('CL=F');
const tny  = q('^TNX');
const krw  = q('KRW=X');

const msg =
  `주요 지수${debugMsg}\n` +
  `• 다우 ${pct(dji.regularMarketChangePercent)}\n` +
  `• S&P500 ${pct(gspc.regularMarketChangePercent)}\n` +
  `• 나스닥 ${pct(ixic.regularMarketChangePercent)}\n\n` +
  `Magnificent 7\n` +
  `• 애플 ${pct(aapl.regularMarketChangePercent)}\n` +
  `• MS ${pct(msft.regularMarketChangePercent)}\n` +
  `• 구글 ${pct(googl.regularMarketChangePercent)}\n` +
  `• 아마존 ${pct(amzn.regularMarketChangePercent)}\n` +
  `• 엔비디아 ${pct(nvda.regularMarketChangePercent)}\n` +
  `• 메타 ${pct(meta.regularMarketChangePercent)}\n` +
  `• 테슬라 ${pct(tsla.regularMarketChangePercent)}\n\n` +
  `매크로\n` +
  `• WTI ${pr(wti.regularMarketPrice)}달러\n` +
  `• 미 10년물 ${pr(tny.regularMarketPrice)}%\n` +
  `• 달러/원 ${pr(krw.regularMarketPrice, 1)}원`;

return [{ json: { message: msg } }];
